 enum MessageAction {
     Copy(usize),
     StartEdit(usize),
     FinishEdit(usize),
     CancelEdit,
     Regenerate,
 }

 enum SidebarAction {
     Load(i64),
     Delete(i64),
     Export(i64),
     StartRename(i64),
     FinishRename(i64),
 }

